DROP TABLE IF EXISTS `career_step_submission_files`;
CREATE TABLE `career_step_submission_files` (
  `id` CHAR(36) NOT NULL,
  `submission_id` CHAR(36) NOT NULL,
  `file_url` LONGTEXT NOT NULL,
  `file_name` LONGTEXT,
  `file_size` INT,
  `uploaded_at` DATETIME(6) NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `career_step_submissions`;
CREATE TABLE `career_step_submissions` (
  `id` CHAR(36) NOT NULL,
  `assignment_id` CHAR(36) NOT NULL,
  `template_id` CHAR(36) NOT NULL,
  `step_order` INT NOT NULL,
  `user_id` CHAR(36) NOT NULL,
  `company_id` CHAR(36),
  `attempt_no` INT NOT NULL,
  `is_reinforced` TINYINT(1) NOT NULL,
  `comment` LONGTEXT,
  `test_attempt_id` CHAR(36),
  `status` LONGTEXT NOT NULL,
  `reviewed_by` CHAR(36),
  `reviewed_at` DATETIME(6),
  `rejection_reason` LONGTEXT,
  `created_at` DATETIME(6) NOT NULL,
  `updated_at` DATETIME(6) NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `career_track_templates`;
CREATE TABLE `career_track_templates` (
  `id` CHAR(36) NOT NULL,
  `company_id` CHAR(36),
  `from_position_id` CHAR(36),
  `to_position_id` CHAR(36),
  `title` LONGTEXT NOT NULL,
  `description` LONGTEXT,
  `motivation_text` LONGTEXT,
  `estimated_months` INT,
  `steps` JSON NOT NULL,
  `is_active` TINYINT(1) NOT NULL,
  `created_by` CHAR(36) NOT NULL,
  `created_at` DATETIME(6) NOT NULL,
  `updated_at` DATETIME(6) NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
