('ef612712-7989-4e25-85ce-ed3978395dcf','a0000000-0000-0000-0000-000000000001','9ccff0aa-8e21-4f90-8da1-2bad3791a05a','107611ad-bc75-4db1-9194-c98e7bf63dfc','Менеджер по продажам → Линейный руководитель','Базовый карьерный трек: рост от менеджера по продажам до линейного руководителя коммерческого блока.','Развивайте лидерские навыки и наставничество — следующий шаг это управление командой продаж.',18,'[{"goals": ["Изучить регламенты и инструменты целевой роли", "Сдать вводный тест", "Познакомиться с командой и зонами ответственности"], "order": 0, "title": "Адаптация и базовые знания", "penalty": "Назначить дополнительное тестирование, выявляющее: (а) изменились ли цели сотрудника, (б) причины срыва перехода на следующий этап, (в) изменилась ли мотивация сотрудника.", "rewards": ["Бейдж «Адаптация пройдена»", "Запись в цифровой паспорт", "Очки лояльности"], "description": "Освоение базовых знаний, инструментов и регламентов, необходимых для перехода с должности «Менеджер по продажам» к должности «Линейный руководитель».", "duration_months": 5, "pass_conditions": ["Завершить онбординг", "Вводный тест ≥ 70%"], "success_metrics": ["Отзыв руководителя ≥ 4/5", "Прохождение контрольного теста ≥ 80%"]}, {"goals": ["Выполнить 3 типовые задачи целевой роли", "Получить положительную обратную связь от наставника", "Закрыть профильный мини-тест"], "order": 1, "title": "Освоение функций целевой роли", "penalty": "Назначить дополнительное тестирование, выявляющее: (а) изменились ли цели сотрудника, (б) причины срыва перехода на следующий этап, (в) изменилась ли мотивация сотрудника.", "rewards": ["Очки лояльности", "Достижение «Уверенный исполнитель»"], "description": "Самостоятельное выполнение типовых задач целевой должности под наставничеством.", "duration_months": 5, "pass_conditions": ["Закрыть KPI этапа ≥ 80%", "Оценка наставника ≥ 4/5"], "success_metrics": ["KPI этапа ≥ 80%", "Оценка руководителя ≥ 4/5"]}, {"goals": ["Возглавить мини-проект", "Менторить нового сотрудника"