INSERT INTO `hr_documents` (`id`,`document_type`,`title`,`description`,`file_url`,`file_name`,`processing_status`,`extracted_data`,`scenario_id`,`created_by`,`created_at`,`updated_at`,`company_id`) VALUES
('ffc2da9e-862f-4c29-a9d9-0f4141b4479a','motivation_strategy','Политика в области вознагараждения персонала 03.09.2023 1',NULL,'https://wwmdzrzguicinvxibbqv.supabase.co/storage/v1/object/sign/hr-documents/motivation_strategy/1776069981635______________________________________________03.09.2023_1.docx?token=eyJraWQiOiJzdG9yYWdlLXVybC1zaWduaW5nLWtleV8xYTU5Y2E4YS1jYWRjLTRmZGUtYWZmOC1hMDEwNjM2ODM4OTQiLCJhbGciOiJIUzI1NiJ9.eyJ1cmwiOiJoci1kb2N1bWVudHMvbW90aXZhdGlvbl9zdHJhdGVneS8xNzc2MDY5OTgxNjM1X19fX19fX19fX19fX19fX19fX19fX19fX19fX19fX19fX19fX19fX19fX19fXzAzLjA5LjIwMjNfMS5kb2N4IiwiaWF0IjoxNzc2MDY5OTgyLCJleHAiOjE3NzYwNzA1ODJ9.4gYRW8j9ZeEHU5sS7TsywgL2_l_GV4yg1nMC_JgqKm4','Политика в области вознагараждения персонала 03.09.2023 1.docx','completed','{"summary": "Документ представляет собой политику компании в области вознаграждения персонала, разработанную для привлечения, мотивации и удержания высококвалифицированных сотрудников. Он описывает принципы, цели, структуру системы вознаграждения, включая базовую заработную плату, переменный доход, премии, доплаты, надбавки и социальный пакет. Особое внимание уделено связи вознаграждения с результативностью труда, квалификацией и рыночной ситуацией. Документ также охватывает аспекты планирования фонда оплаты труда, конфиденциальности и ответственности за реализацию политики.", "scenario": {"title": "Оценка вовлеченности и мотивации персонала в соответствии с Политикой вознаграждения", "questions": [{"criteria": "Оценка глубины понимания сотрудником целей политики вознаграждения, выявление конкретных примеров или предложений по улучшению.", "question": "Как, по вашему мнению, текущая система вознаграждения компании способствует привлечению и удержанию высококвалифицированных сотрудников?", "max_score": 10}, {"criteria": "Способность сотрудника аргументировать свою позицию, выявление уровня удовлетворенности и наличия конструктивных предложений по повышению справедливости.", "question": "Насколько справедливо, по вашей оценке, распределяется переменная часть вознаграждения (премии, бонусы), учитывая ваши личные достижения и вклад в командные цели?", "max_score": 10}, {"criteria": "Оценка понимания сотрудником связи между квалификацией/развитием и вознаграждением. Выявление потребностей в обучении и развитии для увеличения потенциала.", "question": "Как вы считаете, насколько полно система вознаграждения учитывает ваш профессиональный опыт, квалификацию и развитие компетенций?", "max_score": 10}, {"criteria": "Оценка осведомленности сотрудника о предоставляемом социальном пакете и его значимости для личной мотивации.", "question": "Какие элементы социального пакета (ДМС, обучение, корпоративные мероприятия) вы считаете наиболее ценными для себя и почему?", "max_score": 5}, {"criteria": "Выявление нефинансовых мотиваторов, оценка соответствия ценностей сотрудника корпоративной культуре.", "question": "Какие факторы (помимо финансового вознаграждения) являются для вас ключевыми в мотивации к эффективной работе и развитию в компании?", "max_score": 10}, {"criteria": "Оценка лидерских качеств, стратегического мышления и способности применять принципы политики на практике.", "question": "Представьте, что вы руководитель подразделения. Как бы вы использовали Политику вознаграждения для мотивации своей команды и достижения стратегических целей компании?", "max_score": 10}, {"criteria": "Оценка критического мышления, инициативности и способности генерировать конструктивные идеи. Анализ соответствия предложений целям и принципам политики.", "question": "Какие изменения или дополнения вы бы предложили внести в текущую Политику вознаграждения, чтобы сделать ее более эффективной и конкурентоспособной?", "max_score": 15}], "description": "Данный сценарий предназначен для оценки понимания сотрудниками политики вознаграждения, их соответствия ее принципам, а также выявления уровня мотивации и удовлетворенности системой вознаграждения. Оценка проводится в формате структурированных вопросов, позволяющих опередить степень вовлеченности персонала и его готовность к развитию в рамках компании. Результаты оценки могут быть использованы для корректировки мотивационных программ и повышения эффективности HR-стратегии.", "competencies": ["Понимание корпоративных политик", "Мотивация и вовлеченность", "Аналитическое мышление", "Коммуникативные навыки", "Принятие решений", "Стратегическое мышление", "Инновационность"]}, "key_points": ["Привлечение, мотивация и удержание высококвалифицированных сотрудников.", "Справедливая и конкурентоспособная система вознаграждения.", "Связь вознаграждения с результативностью труда, квалификацией и опытом.", "Прозрачность, законность и конфиденциальность в вопросах вознаграждения.", "Включение базовой заработной платы, переменного дохода, доплат, надбавок и социального пакета.", "Формирование фонда оплаты труда на основе среднесрочных планов и бюджетов.", "Регулярная актуализация политики с учетом изменений рынка и законодательства."]}','32ed9ac5-76aa-4e83-9e1c-4698e864dc16','2217c8c3-7907-4dc1-bfc7-9ffb49c66b2f','2026-04-13 08:46:22.752227','2026-04-13 08:47:10.842883',NULL),
('65378dea-1c4c-458a-8e3a-fb88059c738b','motivation_strategy','Политика в области вознагараждения персонала 03.09.2023 1',NULL,'https://wwmdzrzguicinvxibbqv.supabase.co/storage/v1/object/sign/hr-documents/motivation_strategy/1776166958541______________________________________________03.09.2023_1.docx?token=eyJraWQiOiJzdG9yYWdlLXVybC1zaWduaW5nLWtleV8xYTU5Y2E4YS1jYWRjLTRmZGUtYWZmOC1hMDEwNjM2ODM4OTQiLCJhbGciOiJIUzI1NiJ9.eyJ1cmwiOiJoci1kb2N1bWVudHMvbW90aXZhdGlvbl9zdHJhdGVneS8xNzc2MTY2OTU4NTQxX19fX19fX19fX19fX19fX19fX19fX19fX19fX19fX19fX19fX19fX19fX19fXzAzLjA5LjIwMjNfMS5kb2N4IiwiaWF0IjoxNzc2MTY2OTU5LCJleHAiOjE3NzYxNjc1NTl9.WdOa8luxgjzRTWgi-YzNskvu_Ijzg333FTmRCFlWqD0','Политика в области вознагараждения персонала 03.09.2023 1.docx','completed','{"summary": "Документ представляет собой Положение о системе вознаграждения персонала, разработанное в целях повышения мотивации сотрудников, роста производительности труда и достижения стратегических целей компании. В нем описывается общая философия вознаграждения, структура заработной платы, принципы формирования переменной части, критерии ежегодной оценки для целей вознаграждения, а также особенности оплаты труда различных категорий персонала и порядок пересмотра окладов. Основной акцент делается на справедливости, прозрачности, гибкости и соответствии системы вознаграждения рыночным условиям.", "scenario": {"title": "Сценарий ежегодной оценки сотрудников для целей вознаграждения", "questions": [{"criteria": "Оценка результативности на основе достижения KPI, выполнения планов, участия в проектах. Подтверждение конкретными, измеримыми результатами. Соответствие п. 3.2.1 и 3.2.2 документа.", "question": "Насколько эффективно вы достигали поставленных индивидуальных целей и KPI за отчетный период? Приведите конкретные примеры и результаты.", "max_score": 10}, {"criteria": "Оценка вовлеченности в командную работу, инициативы по улучшению общих процессов, вклад в успех компании. Соответствие п. 3.2.1 и 3.2.2 документа.", "question": "Как вы способствовали достижению командных и корпоративных целей? Опишите свой вклад в коллективные результаты.", "max_score": 10}, {"criteria": "Оценка демонстрации корпоративных и профессиональных компетенций, соответствующих стратегическим целям компании. Соответствие п. 3.2.2 документа.", "question": "Какие из ключевых компетенций, необходимых для вашей должности и развития компании, вы проявили наиболее ярко в течение года? Приведите примеры поведения.", "max_score": 10}, {"criteria": "Выявление исключительной производительности, инновационных решений, или значимого вклада, выходящего за рамки обычных обязанностей. Соответствие п. 3.2.1 и разделу 4 (виды премий).", "question": "Опишите ситуации, в которых вы превзошли ожидания или продемонстрировали выдающиеся результаты. Какие были достигнуты ключевые показатели?", "max_score": 10}, {"criteria": "Оценка самоанализа, осознания зон роста и наличия плана развития. Соответствие п. 3.2.2 (оценка для выявления областей для развития и обучения).", "question": "Какие области для развития вы определили для себя на следующий отчетный период? Какие шаги планируете предпринять для улучшения своих навыков и повышения эффективности?", "max_score": 10}, {"criteria": "Оценка понимания сотрудником принципов системы вознаграждения, сбор обратной связи для дальнейшего улучшения системы. Соответствие п. 2.2 и 2.3 документа.", "question": "Как вы оцениваете справедливость и прозрачность системы вознаграждения в компании? Предложите, если есть, идеи по её улучшению.", "max_score": 5}], "description": "Данный сценарий предназначен для проведения ежегодной оценки эффективности сотрудников в соответствии с Положением о системе вознаграждения, с целью определения переменной части заработной платы и выявления областей для развития. Оценка основывается на достижении личных, командных и корпоративных целей, а также на демонстрации ключевых компетенций.", "competencies": ["Достижение результата", "Работа в команде", "Инициативность", "Коммуникабельность", "Профессионализм", "Саморазвитие", "Аналитическое мышление (для руководящих позиций)", "Лидерство (для руководящих позиций)"]}, "key_points": ["Система вознаграждения направлена на мотивацию, рост производительности и достижение стратегических целей.", "Вознаграждение состоит из постоянной (оклад) и переменной (премии, бонусы) частей.", "Переменная часть зависит от личных, командных и корпоративных результатов, а также от ежегодной оценки сотрудников.", "Принципы системы: справедливость, прозрачность, гибкость, конкурентоспособность, регулярный пересмотр.", "Ежегодная оценка персонала проводится с целью определения ключевых показателей индивидуальной эффективности (KPI) и уровня достижения целей.", "Документ регламентирует порядок начисления различных видов премий, доплат и компенсаций.", "Система оплаты труда ориентирована на рыночную привлекательность и внутреннюю справедливость."]}',NULL,'856bd219-bc77-4d90-980d-2e1f3f105851','2026-04-14 11:42:39.606336','2026-04-14 11:42:49.349870','a0000000-0000-0000-0000-000000000001'),
('c87cf7ac-4895-444a-ac12-d71c3b0bf10f','talent_management','ПОлитика _по_управлению талантами',NULL,'https://wwmdzrzguicinvxibbqv.supabase.co/storage/v1/object/sign/hr-documents/talent_management/1776166910812__________________________________.docx?token=eyJraWQiOiJzdG9yYWdlLXVybC1zaWduaW5nLWtleV8xYTU5Y2E4YS1jYWRjLTRmZGUtYWZmOC1hMDEwNjM2ODM4OTQiLCJhbGciOiJIUzI1NiJ9.eyJ1cmwiOiJoci1kb2N1bWVudHMvdGFsZW50X21hbmFnZW1lbnQvMTc3NjE2NjkxMDgxMl9fX19fX19fX19fX19fX19fX19fX19fX19fX19fX19fX18uZG9jeCIsImlhdCI6MTc3NjE2NjkxMSwiZXhwIjoxNzc2MTY3NTExfQ.LuLdbz5SE11GhZNonho0mahcxYpi8IoYOyIP8fSeDrI','ПОлитика _по_управлению талантами.docx','completed','{"summary": "Документ представляет собой политику по управлению талантами, охватывающую четыре ключевых направления: привлечение, развитие, удержание и стратегическое планирование. Основная цель политики – создание эффективной системы привлечения, развития, удержания и мотивации высококвалифицированных сотрудников, а также обеспечение устойчивого роста и развития компании.", "scenario": {"title": "Сценарий оценки сотрудника в рамках политики управления талантами", "questions": [{"criteria": "Оценивается понимание сотрудником своей значимости и вклада в стратегические цели. Насколько его роль отражает принципы эффективности и развития компании.", "question": "Какую роль в вашем текущем проекте вы считаете наиболее значимой для достижения общих целей компании?", "max_score": 10}, {"criteria": "Оценивается инициативность сотрудника в саморазвитии. Наличие конкретных примеров обучения (курсы, менторство, коучинг), применения новых знаний на практике.", "question": "Какие методы вы используете для повышения своих профессиональных навыков и знаний в соответствии с требованиями вашей должности и стратегическими целями компании?", "max_score": 10}, {"criteria": "Оцениваются аналитические способности, умение применять знания на практике, способность к решению проблем, инициативность и стремление к улучшениям.", "question": "Опишите ситуацию, когда вы успешно применили свои знания и навыки для решения сложной задачи или улучшения рабочего процесса. Что стало ключевым фактором успеха?", "max_score": 10}, {"criteria": "Оценивается амбициозность, стремление к развитию, соответствие карьерных планов возможностям компании, наличие конкретных шагов по достижению целей.", "question": "Как вы видите свой карьерный рост в компании в ближайшие 3-5 лет? Какие шаги вы предпринимаете для достижения этих целей?", "max_score": 10}, {"criteria": "Оценивается осознанность сотрудником корпоративных ценностей, их интеграция в работу. Наличие конкретных примеров, иллюстрирующих применение ценностей на практике.", "question": "Какие из наших корпоративных ценностей вы считаете наиболее важными для вашей работы и как вы их реализуете в повседневной деятельности?", "max_score": 10}, {"criteria": "Оценивается вклад сотрудника в командную работу, коммуникативные навыки, способности к сотрудничеству, проявление инициативы в создании позитивной атмосферы.", "question": "Как вы способствуете формированию благоприятного рабочего климата и развитию командного взаимодействия?", "max_score": 10}, {"criteria": "Оценивается уровень саморефлексии, осознание своих мотивирующих факторов, конструктивность предложений по улучшению рабочей среды.", "question": "Какие факторы, по вашему мнению, наиболее сильно влияют на вашу мотивацию в текущей работе? Что можно улучшить для повышения вашей вовлеченности?", "max_score": 10}, {"criteria": "Оценивается способность сотрудника воспринимать и использовать обратную связь (позитивная открытость к критике, умение трансформировать ее в план развития).", "question": "Опишите, как вы используете обратную связь от коллег и руководителей для своего развития.", "max_score": 10}, {"criteria": "Оценивается проактивность сотрудника, его готовность брать на себя новые обязанности, желание обучаться и расти внутри компании.", "question": "Какие новые задачи или проекты вы бы хотели попробовать в ближайшее время, чтобы расширить свой опыт?", "max_score": 10}], "description": "Данный сценарий предназначен для оценки сотрудников с целью выявления их потенциала, определения потребностей в развитии и планирования карьерного роста в соответствии с политикой управления талантами компании. Оценка проводится ежегодно и включает самооценку, оценку непосредственным руководителем и последующее обсуждение.", "competencies": ["Профессиональное развитие и обучение", "Решение проблем и инновации", "Карьерное планирование и амбиции", "Корпоративные ценности и этика", "Командная работа и коммуникация", "Мотивация и вовлеченность", "Открытость к обратной связи", "Проактивность и инициативность"]}, "key_points": ["Комплексный подход к управлению талантами, включающий привлечение, развитие, удержание и стратегическое планирование.", "Важность внутренних и внешних источников привлечения талантов при условии соблюдения прозрачности и объективности.", "Непрерывное развитие сотрудников через обучение, коучинг, менторство, ротацию и программы развития лидеров.", "Удержание талантов через конкурентное вознаграждение, создание благоприятного рабочего климата, возможности карьерного роста и признание достижений.", "Стратегическое планирование для выявления будущих потребностей в талантах и создания кадрового резерва.", "Важность обратной связи, регулярной оценки и развития сотрудников.", "Акцент на создании культуры открытости, доверия и взаимного уважения."]}',NULL,'856bd219-bc77-4d90-980d-2e1f3f105851','2026-04-14 11:41:52.200283','2026-04-14 11:42:04.862063','a0000000-0000-0000-0000-000000000001'),
('7ca8ce6f-baa9-483a-90a5-e43d24f7c205','hr_strategy','HR Strategy_20251114_vF',NULL,'https://wwmdzrzguicinvxibbqv.supabase.co/storage/v1/object/sign/hr-documents/hr_strategy/1776166945709_HR_Strategy_20251114_vF.pdf?token=eyJraWQiOiJzdG9yYWdlLXVybC1zaWduaW5nLWtleV8xYTU5Y2E4YS1jYWRjLTRmZGUtYWZmOC1hMDEwNjM2ODM4OTQiLCJhbGciOiJIUzI1NiJ9.eyJ1cmwiOiJoci1kb2N1bWVudHMvaHJfc3RyYXRlZ3kvMTc3NjE2Njk0NTcwOV9IUl9TdHJhdGVneV8yMDI1MTExNF92Ri5wZGYiLCJpYXQiOjE3NzYxNjY5NTIsImV4cCI6MTc3NjE2NzU1Mn0.jSTFYGZgU1wlcEHAGVX12QgkN_dv1aRKJy5SDApE0sg','HR Strategy_20251114_vF.pdf','completed','{"summary": "Документ представляет собой HR-стратегию, скорее всего, для крупной международной компании, судя по упомянутым характеристикам и широкому спектру тем. Документ делает акцент на трансформацию HR-функции, развитие персонала, поддержание вовлеченности и создания адаптивной корпоративной культуры. Ключевые аспекты включают цифровизацию HR, стратегическое планирование талантов, управление производительностью и создание инклюзивной среды. Цель стратегии - усилить конкурентные преимущества компании через эффективное управление человеческим капиталом.", "scenario": {"title": "Сценарий оценки сотрудника: Эффективность и Адаптивность в Цифровой HR-Трансформации", "questions": [{"criteria": "Оценка: 0-3 балла за каждый используемый инструмент (не используются/используются формально/используются регулярно/используются для оптимизации). 0-4 балла за конкретные примеры и объяснения (отсутствуют/поверхностные/удовлетворительные/детальные и вдохновляющие).", "question": "Как вы использовали новые цифровые HR-инструменты (например, платформы для обучения, системы управления проектами, аналитические дашборды) в своей работе за последний год? Приведите конкретные примеры и опишите, как они помогли вам повысить эффективность.", "max_score": 10}, {"criteria": "Оценка: 0-3 балла за инициативность и проактивность. 0-4 балла за описание процесса обучения и адаптации. 0-3 балла за достигнутые результаты и их влияние на работу/команду.", "question": "Опишите ситуацию, когда вам потребовалось быстро освоить новый навык или адаптироваться к изменяющимся требованиям работы. Какие шаги вы предприняли для этого, и каков был результат?", "max_score": 10}, {"criteria": "Оценка: 0-3 балла за понимание принципов инклюзивности. 0-4 балла за конкретные примеры инициатив/действий. 0-3 балла за видимое влияние на командную динамику и вовлеченность.", "question": "Как вы способствуете созданию инклюзивной и поддерживающей рабочей среды в вашей команде? Приведите примеры ваших действий и их влияния.", "max_score": 10}, {"criteria": "Оценка: 0-3 балла за демонстрацию инициативы. 0-4 балла за описание лидерских действий (наставничество, координация, мотивация). 0-3 балла за достигнутый результат и признание со стороны коллег.", "question": "Расскажите о проекте или задаче, где вам пришлось проявить лидерские качества, даже если вы не занимаете формальную руководящую должность. Что было вашей ролью и каким был результат?", "max_score": 10}, {"criteria": "Оценка: 0-3 балла за регулярность и качество обратной связи. 0-4 балла за демонстрацию активного слушания и конструктивной обратной связи. 0-3 балла за примеры изменений в поведении/работе на основе обратной связи.", "question": "Какую обратную связь (как позитивную, так и развивающую) вы давали или получали за последний год? Как вы использовали эту обратную связь для профессионального роста?", "max_score": 10}], "description": "Данный сценарий предназначен для оценки эффективности сотрудников в контексте реализации новой HR-стратегии, с акцентом на их адаптивность к цифровым инструментам, способность к развитию и вклад в создание поддерживающей корпоративной культуры. Оценка проводится в формате полуструктурированного интервью с элементами самооценки и оценки 360 градусов.", "competencies": ["Адаптивность и гибкость", "Обучаемость и развитие", "Использование цифровых инструментов", "Лидерство и влияние", "Коллаборация и инклюзивность", "Проактивность и инициативность", "Управление производительностью"]}, "key_points": ["HR-трансформация и цифровизация: внедрение новых технологий (AI, машинное обучение) для оптимизации HR-процессов, таких как рекрутинг, онбординг, обучение и управление производительностью. Развитие аналитики данных для принятия более обоснованных решений.", "Стратегическое планирование талантов и развитие навыков: обеспечение наличия необходимых талантов для будущих потребностей бизнеса. Фокус на развитии новых навыков, переквалификации и повышении квалификации сотрудников.", "Культура вовлеченности и благополучия: создание позитивной и инклюзивной рабочей среды, поддержание благополучия сотрудников, усиление коммуникации и признания.", "Управление производительностью и эффективность: переосмысление подходов к оценке и управлению производительностью, сосредоточение на постоянном развитии и обратной связи.", "Лидерство и организационное развитие: развитие лидерских качеств, способствующих изменениям и инновациям. Построение гибкой и адаптивной организационной структуры."]}','e44b0df5-77e8-4d8b-836c-f35ac3af2958','856bd219-bc77-4d90-980d-2e1f3f105851','2026-04-14 11:42:32.935731','2026-04-14 11:43:26.188243','a0000000-0000-0000-0000-000000000001');

DROP TABLE IF EXISTS `hr_task_assignees`;
CREATE TABLE `hr_task_assignees` (
  `id` CHAR(36) NOT NULL,
  `task_id` CHAR(36) NOT NULL,
  `user_id` CHAR(36) NOT NULL,
  `individual_status` LONGTEXT NOT NULL,
  `reward_paid` TINYINT(1) NOT NULL,
  `created_at` DATETIME(6) NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `hr_tasks`;
CREATE TABLE `hr_tasks` (
  `id` CHAR(36) NOT NULL,
  `company_id` CHAR(36) NOT NULL,
  `created_by` CHAR(36) NOT NULL,
  `title` LONGTEXT NOT NULL,
  `description` LONGTEXT,
  `category` LONGTEXT NOT NULL,
  `reward_coins` INT NOT NULL,
  `deadline` DATE,
  `status` LONGTEXT NOT NULL,
  `reviewed_by` CHAR(36),
  `reviewed_at` DATETIME(6),
  `created_at` DATETIME(6) NOT NULL,
  `updated_at` DATETIME(6) NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `notifications`;
CREATE TABLE `notifications` (
  `id` CHAR(36) NOT NULL,
  `user_id` CHAR(36) NOT NULL,
  `title` LONGTEXT NOT NULL,
  `description` LONGTEXT,
  `notification_type` LONGTEXT NOT NULL,
  `is_read` TINYINT(1) NOT NULL,
  `created_at` DATETIME(6) NOT NULL,
  `company_id` CHAR(36),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
