DROP TABLE IF EXISTS `peer_recognition_reactions`;
CREATE TABLE `peer_recognition_reactions` (
  `id` CHAR(36) NOT NULL,
  `recognition_id` CHAR(36) NOT NULL,
  `user_id` CHAR(36) NOT NULL,
  `reaction` LONGTEXT NOT NULL,
  `created_at` DATETIME(6) NOT NULL,
  PRIMARY KEY (`id`)
