  `coin_reward` INT NOT NULL,
  `created_at` DATETIME(6) NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `position_career_paths`;
CREATE TABLE `position_career_paths` (
  `id` CHAR(36) NOT NULL,
  `from_position_id` CHAR(36) NOT NULL,
