INSERT INTO `position_career_paths` (`id`,`from_position_id`,`to_position_id`,`strategy_description`,`requirements`,`estimated_months`,`created_by`,`created_at`,`updated_at`,`company_id`) VALUES
('6d21752f-7639-4d73-9895-49ca384454f9','a612b68b-84f5-4743-800b-d27a8e6b469f','cf62e14d-f1fa-43e6-b2f7-8d45709779a9','Развитие навыков работы с персоналом, изучение HR-процессов и получение дополнительного образования в области HR для перехода из бэк-офиса в HR.','[]',24,'82c3428f-edad-412e-8f44-40070830ecfd','2026-04-13 10:32:05.630931','2026-04-13 10:32:05.630931','a0000000-0000-0000-0000-000000000001'),
('4993d0e7-88bd-4e35-8446-e7e801e6be21','cf62e14d-f1fa-43e6-b2f7-8d45709779a9','107611ad-bc75-4db1-9194-c98e7bf63dfc','Проявление лидерских качеств, участие в проектах по оптимизации HR-процессов, освоение управленческих навыков для повышения до линейного руководителя в функциональных подразделениях.','[]',36,'82c3428f-edad-412e-8f44-40070830ecfd','2026-04-13 10:32:05.630931','2026-04-13 10:32:05.630931','a0000000-0000-0000-0000-000000000001'),
('8a9bcd7c-2565-4171-b08d-01a2400fe426','9ccff0aa-8e21-4f90-8da1-2bad3791a05a','40f1195d-ece7-4b98-a790-a28615c51791','Развитие аналитических навыков, углубленное изучение рынка и продуктов компании, освоение инструментов анализа данных для горизонтального перехода в роль аналитика.','[]',30,'82c3428f-edad-412e-8f44-40070830ecfd','2026-04-13 10:32:05.630931','2026-04-13 10:32:05.630931','a0000000-0000-0000-0000-000000000001'),
('d914d0dd-14c4-467b-b698-ee7579934f04','9ccff0aa-8e21-4f90-8da1-2bad3791a05a','107611ad-bc75-4db1-9194-c98e7bf63dfc','Достижение высоких показателей в продажах, развитие управленческих навыков, наставничество младших специалистов для перехода на позицию линейного руководителя в коммерческом подразделении.','[]',36,'82c3428f-edad-412e-8f44-40070830ecfd','2026-04-13 10:32:05.630931','2026-04-13 10:32:05.630931','a0000000-0000-0000-0000-000000000001'),
('ceb5056e-443e-4553-8395-8b056c89f16c','583fd82b-21bf-4f84-82be-ca7ecd8694ff','5cd4eb9a-90d9-4829-80ee-419ec03a7bcb','Участие в технических проектах, развитие навыков управления, коммуникации с заказчиками и командами для горизонтального перехода в менеджеры проектов.','[]',36,'82c3428f-edad-412e-8f44-40070830ecfd','2026-04-13 10:32:05.630931','2026-04-13 10:32:05.630931','a0000000-0000-0000-0000-000000000001'),
('c7a9ba9e-4684-4b96-b6ef-a0bc83ab181e','583fd82b-21bf-4f84-82be-ca7ecd8694ff','107611ad-bc75-4db1-9194-c98e7bf63dfc','Демонстрация глубоких технических знаний, эффективное решение сложных проблем, развитие лидерских качеств для повышения до линейного руководителя в технических подразделениях.','[]',36,'82c3428f-edad-412e-8f44-40070830ecfd','2026-04-13 10:32:05.630931','2026-04-13 10:32:05.630931','a0000000-0000-0000-0000-000000000001'),
('25a87620-55b7-41c7-9ad6-b76b7685be34','5cd4eb9a-90d9-4829-80ee-419ec03a7bcb','107611ad-bc75-4db1-9194-c98e7bf63dfc','Успешное управление крупными и сложными проектами, наставничество младших менеджеров, развитие стратегического мышления для перехода на позицию линейного руководителя в подразделениях развития.','[]',24,'82c3428f-edad-412e-8f44-40070830ecfd','2026-04-13 10:32:05.630931','2026-04-13 10:32:05.630931','a0000000-0000-0000-0000-000000000001'),
('ce0d2b18-e024-45c6-bbf5-facb02e48037','40f1195d-ece7-4b98-a790-a28615c51791','107611ad-bc75-4db1-9194-c98e7bf63dfc','Углубление аналитической экспертизы, предоставление стратегических рекомендаций, лидерство в проектах по анализу данных для повышения до линейного руководителя с аналитической направленностью.','[]',30,'82c3428f-edad-412e-8f44-40070830ecfd','2026-04-13 10:32:05.630931','2026-04-13 10:32:05.630931','a0000000-0000-0000-0000-000000000001'),
('72eec530-f6ab-4caf-90dd-f532ca1535aa','107611ad-bc75-4db1-9194-c98e7bf63dfc','cd512374-7332-4705-8e29-6904a6c23751','Успешное управление отделами/проектами, демонстрация стратегического видения, развитие навыков межфункционального взаимодействия и принятия решений на высшем уровне для перехода на позицию руководителя.','[]',48,'82c3428f-edad-412e-8f44-40070830ecfd','2026-04-13 10:32:05.630931','2026-04-13 10:32:05.630931','a0000000-0000-0000-0000-000000000001');

DROP TABLE IF EXISTS `positions`;
CREATE TABLE `positions` (
  `id` CHAR(36) NOT NULL,
  `title` LONGTEXT NOT NULL,
  `description` LONGTEXT,
  `department` LONGTEXT,
  `psychological_profile` JSON,
  `competency_profile` JSON,
  `created_by` CHAR(36) NOT NULL,
  `created_at` DATETIME(6) NOT NULL,
  `updated_at` DATETIME(6) NOT NULL,
  `company_id` CHAR(36),
  `profile_status` LONGTEXT NOT NULL,
  `profile_version` INT NOT NULL,
  `profile_template` JSON NOT NULL,
  `approved_by` CHAR(36),
  `approved_at` DATETIME(6),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
INSERT INTO `positions` (`id`,`title`,`description`,`department`,`psychological_profile`,`competency_profile`,`created_by`,`created_at`,`updated_at`,`company_id`,`profile_status`,`profile_version`,`profile_template`,`approved_by`,`approved_at`) VALUES
('68327e63-1aec-4fdb-9e3c-254fcb94ef0c','Генеральный директор','Высшее должностное лицо компании, ответственное за стратегическое планирование, управление всеми направлениями деятельности, обеспечение роста и прибыльности компании, а также представление интересов компании на внешнем уровне.','Высшее руководство','[{"level": "высокое", "trait": "Ответственность"}, {"level": "высокое", "trait": "Инициативность"}, {"level": "высокое", "trait": "Стрессоустойчивость"}, {"level": "выше среднего", "trait": "Амбициозность"}, {"level": "высокое", "trait": "Аналитический склад ума"}]','[{"name": "Стратегическое мышление", "required_level": 10}, {"name": "Лидерство", "required_level": 10}, {"name": "Финансовый менеджмент", "required_level": 9}, {"name": "Управление изменениями", "required_level": 9}, {"name": "Принятие решений", "required_level": 10}, {"name": "Коммуникации", "required_level": 9}]','2217c8c3-7907-4dc1-bfc7-9ffb49c66b2f','2026-04-13 08:39:51.331830','2026-04-13 08:39:51.331830',NULL,'draft',1,'{}',NULL,NULL),
('947df9d0-b03a-478d-9e5e-5ebc66bd4009','Заместитель Генерального директора','Оказывает поддержку Генеральному директору в стратегическом управлении, координирует работу нескольких функциональных блоков, принимает оперативные решения и замещает Генерального директора в его отсутствие.','Высшее руководство','[{"level": "высокое", "trait": "Ответственность"}, {"level": "высокое", "trait": "Ориентация на результат"}, {"level": "выше среднего", "trait": "Гибкость мышления"}, {"level": "выше среднего", "trait": "Коммуникабельность"}, {"level": "высокое", "trait": "Решительность"}]','[{"name": "Стратегическое планирование", "required_level": 9}, {"name": "Межфункциональное взаимодействие", "required_level": 9}, {"name": "Управление проектами", "required_level": 8}, {"name": "Развитие бизнеса", "required_level": 8}, {"name": "Наставничество", "required_level": 7}, {"name": "Ведение переговоров", "required_level": 8}]','2217c8c3-7907-4dc1-bfc7-9ffb49c66b2f','2026-04-13 08:39:51.494852','2026-04-13 08:39:51.494852',NULL,'draft',1,'{}',NULL,NULL),
('694f7f84-5e2a-414e-ad02-065f86ba8f1b','Руководитель функционального блока','Отвечает за стратегическое развитие и операционное управление конкретным функциональным блоком (например, маркетинг, финансы, IT, продажи). Формирует и реализует политику блока, управляет командой и бюджетом.','Функциональные блоки','[{"level": "высокое", "trait": "Системность мышления"}, {"level": "выше среднего", "trait": "Лидерские качества"}, {"level": "высокое", "trait": "Ответственность"}, {"level": "выше среднего", "trait": "Самостоятельность"}, {"level": "среднее", "trait": "Оптимизм"}]','[{"name": "Управленческие навыки", "required_level": 9}, {"name": "Экспертиза в области функционала", "required_level": 9}, {"name": "Бюджетирование", "required_level": 8}, {"name": "Управление командой", "required_level": 8}, {"name": "Анализ данных", "required_level": 7}, {"name": "Решение проблем", "required_level": 8}]','2217c8c3-7907-4dc1-bfc7-9ffb49c66b2f','2026-04-13 08:39:51.608919','2026-04-13 08:39:51.608919',NULL,'draft',1,'{}',NULL,NULL),
('3b2b8ada-323c-440c-9087-4af700999646','Менеджер по развитию функционального блока','Разрабатывает и внедряет инициативы по оптимизации процессов и повышению эффективности в рамках функционального блока. Анализирует тренды рынка и предлагает новые подходы.','Функциональные блоки','[{"level": "выше среднего", "trait": "Инициативность"}, {"level": "высокое", "trait": "Любознательность"}, {"level": "выше среднего", "trait": "Внимательность к деталям"}, {"level": "среднее", "trait": "Упорство"}, {"level": "выше среднего", "trait": "Гибкость"}]','[{"name": "Аналитическое мышление", "required_level": 8}, {"name": "Исследовательские навыки", "required_level": 7}, {"name": "Проектный менеджмент", "required_level": 7}, {"name": "Презентационные навыки", "required_level": 6}, {"name": "Критическое мышление", "required_level": 7}, {"name": "Креативность", "required_level": 7}]','2217c8c3-7907-4dc1-bfc7-9ffb49c66b2f','2026-04-13 08:39:51.747628','2026-04-13 08:39:51.747628',NULL,'draft',1,'{}',NULL,NULL),
('24ac6a7d-5800-4b0c-8381-7d1a58fa017d','Специалист функционального блока','Выполняет специализированные задачи в рамках своего функционального блока, использует профессиональные знания и навыки для решения операционных задач.','Функциональные блоки','[{"level": "выше среднего", "trait": "Аккуратность"}, {"level": "высокое", "trait": "Внимательность"}, {"level": "выше среднего", "trait": "Ответственность"}, {"level": "среднее", "trait": "Самостоятельность"}, {"level": "среднее", "trait": "Спокойствие"}]','[{"name": "Профессиональные знания", "required_level": 7}, {"name": "Исполнительность", "required_level": 8}, {"name": "Работа с информацией", "required_level": 6}, {"name": "Компьютерная грамотность", "required_level": 7}, {"name": "Самоорганизация", "required_level": 6}, {"name": "Деловая переписка", "required_level": 5}]','2217c8c3-7907-4dc1-bfc7-9ffb49c66b2f','2026-04-13 08:39:51.890011','2026-04-13 08:39:51.890011',NULL,'draft',1,'{}',NULL,NULL),
('a4d0fbd7-4d2d-40c4-b2ff-df4a79167501','Лидер команды','Возглавляет конкретную команду в рамках функционального блока, отвечает за координацию работы, распределение задач, мотивацию участников команды и достижение поставленных целей проекта или направления.','Команды функционального блока','[{"level": "высокое", "trait": "Лидерские качества"}, {"level": "выше среднего", "trait": "Эмпатия"}, {"level": "высокое", "trait": "Ответственность"}, {"level": "высокое", "trait": "Коммуникабельность"}, {"level": "выше среднего", "trait": "Целеустремленность"}]','[{"name": "Управление командой", "required_level": 8}, {"name": "Планирование и организация", "required_level": 8}, {"name": "Решение конфликтов", "required_level": 7}, {"name": "Наставничество", "required_level": 7}, {"name": "Мотивация персонала", "required_level": 7}, {"name": "Обратная связь", "required_level": 7}]','2217c8c3-7907-4dc1-bfc7-9ffb49c66b2f','2026-04-13 08:39:52.011886','2026-04-13 08:39:52.011886',NULL,'draft',1,'{}',NULL,NULL),
('5a794c97-33f8-4356-b3f4-be4b18b2ce0c','Секретарь Правления','Обеспечивает организационную поддержку работы Правления: подготовка повестки дня, ведение протоколов заседаний, рассылка материалов, контроль исполнения решений.','Члены Правления','[{"level": "высокое", "trait": "Аккуратность"}, {"level": "высокое", "trait": "Ответственность"}, {"level": "высокое", "trait": "Пунктуальность"}, {"level": "среднее", "trait": "Консервативность"}, {"level": "выше среднего", "trait": "Стрессоустойчивость"}]','[{"name": "Делопроизводство", "required_level": 8}, {"name": "Организаторские способности", "required_level": 7}, {"name": "Конфиденциальность", "required_level": 9}, {"name": "Владение MS Office", "required_level": 8}, {"name": "Ведение деловой переписки", "required_level": 7}, {"name": "Тайм-менеджмент", "required_level": 7}]','2217c8c3-7907-4dc1-bfc7-9ffb49c66b2f','2026-04-13 08:39:52.659868','2026-04-13 08:39:52.659868',NULL,'draft',1,'{}',NULL,NULL),
('240cb707-a995-472c-890e-aded5ab8a709','Старший член команды','Оказывает поддержку Лидеру команды, выступает в роли наставника для младших сотрудников, выполняет наиболее сложные задачи, участвует в разработке решений и контроле качества.','Команды функционального блока','[{"level": "высокое", "trait": "Ответственность"}, {"level": "высокое", "trait": "Надежность"}, {"level": "выше среднего", "trait": "Ориентация на качество"}, {"level": "среднее", "trait": "Инициативность"}, {"level": "выше среднего", "trait": "Методичность"}]','[{"name": "Профессиональная экспертиза", "required_level": 8}, {"name": "Самостоятельность", "required_level": 7}, {"name": "Наставничество", "required_level": 6}, {"name": "Решение проблем", "required_level": 7}, {"name": "Анализ задач", "required_level": 7}, {"name": "Декомпозиция задач", "required_level": 7}]','2217c8c3-7907-4dc1-bfc7-9ffb49c66b2f','2026-04-13 08:39:52.120736','2026-04-13 08:39:52.120736',NULL,'draft',1,'{}',NULL,NULL),
('6b3dcb99-2ca3-4b77-9d1d-ef4ca3a62313','Функциональный руководитель','Отвечает за развитие и операционное управление конкретным функциональным направлением (например, HR, IT, Финансы), разрабатывает и внедряет стандарты, методики и процедуры в своей сфере.','Функциональные руководители','[{"level": "высокое", "trait": "Системность мышления"}, {"level": "высокое", "trait": "Ответственность"}, {"level": "выше среднего", "trait": "Требовательность"}, {"level": "выше среднего", "trait": "Стрессоустойчивость"}, {"level": "выше среднего", "trait": "Коммуникабельность"}]','[{"name": "Экспертиза в функциональной области", "required_level": 9}, {"name": "Управление процессами", "required_level": 8}, {"name": "Развитие персонала", "required_level": 7}, {"name": "Анализ и оптимизация", "required_level": 8}, {"name": "Взаимодействие с внешними партнерами", "required_level": 7}, {"name": "Регулирование", "required_level": 8}]','2217c8c3-7907-4dc1-bfc7-9ffb49c66b2f','2026-04-13 08:39:52.763768','2026-04-13 08:39:52.763768',NULL,'draft',1,'{}',NULL,NULL),
('c5e2d8ef-a76a-4852-8764-a45f5037b9f3','Член команды','Выполняет поставленные задачи в рамках проекта или направления, активно участвует в командной работе, отчитывается о проделанной работе Лидеру команды.','Команды функционального блока','[{"level": "высокое", "trait": "Дисциплинированность"}, {"level": "выше среднего", "trait": "Ответственность"}, {"level": "среднее", "trait": "Общительность"}, {"level": "выше среднего", "trait": "Усердие"}, {"level": "высокое", "trait": "Пунктуальность"}]','[{"name": "Исполнительность", "required_level": 8}, {"name": "Работа в команде", "required_level": 7}, {"name": "Владение специализированным ПО", "required_level": 6}, {"name": "Обучаемость", "required_level": 7}, {"name": "Тайм-менеджмент", "required_level": 6}, {"name": "Инициативность", "required_level": 5}]','2217c8c3-7907-4dc1-bfc7-9ffb49c66b2f','2026-04-13 08:39:52.223694','2026-04-13 08:39:52.223694',NULL,'draft',1,'{}',NULL,NULL),
('3714aa00-a2cc-4f42-92c7-818e81c0b6fd','Главный специалист функционального направления','Выполняет ключевые экспертные задачи в рамках функционального направления, разрабатывает сложные решения, консультирует коллег и участвует в стратегическом планировании направления.','Функциональные руководители','[{"level": "высокое", "trait": "Аналитический склад ума"}, {"level": "высокое", "trait": "Внимательность к деталям"}, {"level": "высокое", "trait": "Ответственность"}, {"level": "выше среднего", "trait": "Инициативность"}, {"level": "выше среднего", "trait": "Любознательность"}]','[{"name": "Глубокая профессиональная экспертиза", "required_level": 9}, {"name": "Исследовательские навыки", "required_level": 8}, {"name": "Аналитическое мышление", "required_level": 8}, {"name": "Разработка методологий", "required_level": 8}, {"name": "Консультирование", "required_level": 7}, {"name": "Самостоятельность", "required_level": 8}]','2217c8c3-7907-4dc1-bfc7-9ffb49c66b2f','2026-04-13 08:39:52.869036','2026-04-13 08:39:52.869036',NULL,'draft',1,'{}',NULL,NULL),
('e22bde0a-3c4e-44ad-b2b5-5e6d9cc4720a','Младший член команды','Выполняет простые задачи под руководством старших коллег, осваивает новые навыки и технологии, активно участвует в процессе обучения и развития.','Команды функционального блока','[{"level": "высокое", "trait": "Любознательность"}, {"level": "выше среднего", "trait": "Усидчивость"}, {"level": "высокое", "trait": "Внимательность"}, {"level": "среднее", "trait": "Ответственность"}, {"level": "среднее", "trait": "Скромность"}]','[{"name": "Обучаемость", "required_level": 8}, {"name": "Исполнительность", "required_level": 7}, {"name": "Внимание к деталям", "required_level": 6}, {"name": "Базовые профессиональные знания", "required_level": 5}, {"name": "Работа с документацией", "required_level": 5}, {"name": "Поиск информации", "required_level": 5}]','2217c8c3-7907-4dc1-bfc7-9ffb49c66b2f','2026-04-13 08:39:52.361552','2026-04-13 08:39:52.361552',NULL,'draft',1,'{}',NULL,NULL),
('eafb39ba-134b-4eb4-b355-bfeefc67af7f','Специалист функционального направления','Осуществляет операционную деятельность в рамках функционального направления, выполняет задачи в соответствии с установленными процедурами и стандартами, участвует в проектах.','Функциональные руководители','[{"level": "высокое", "trait": "Аккуратность"}, {"level": "выше среднего", "trait": "Ответственность"}, {"level": "выше среднего", "trait": "Самоорганизованность"}, {"level": "высокое", "trait": "Внимательность"}, {"level": "среднее", "trait": "Общительность"}]','[{"name": "Профессиональные знания", "required_level": 7}, {"name": "Исполнительность", "required_level": 8}, {"name": "Работа с данными", "required_level": 7}, {"name": "Соблюдение регламентов", "required_level": 8}, {"name": "Софт скиллы", "required_level": 6}, {"name": "Ориентация на результат", "required_level": 6}]','2217c8c3-7907-4dc1-bfc7-9ffb49c66b2f','2026-04-13 08:39:52.970558','2026-04-13 08:39:52.970558',NULL,'draft',1,'{}',NULL,NULL),
('ee85833f-7490-40da-9f03-805e3f7ba71b','Председатель Правления','Руководит заседаниями Правления, обеспечивает выработку и принятие стратегических решений, контроль над их исполнением, взаимодействие с Генеральным директором и акционерами.','Члены Правления','[{"level": "высокое", "trait": "Ответственность"}, {"level": "высокое", "trait": "Влиятельность"}, {"level": "высокое", "trait": "Рассудительность"}, {"level": "высокое", "trait": "Уверенность в себе"}, {"level": "выше среднего", "trait": "Беспристрастность"}]','[{"name": "Стратегическое управление", "required_level": 10}, {"name": "Корпоративное управление", "required_level": 9}, {"name": "Принятие решений", "required_level": 10}, {"name": "Ведение переговоров", "required_level": 9}, {"name": "Анализ рисков", "required_level": 9}, {"name": "Публичные выступления", "required_level": 8}]','2217c8c3-7907-4dc1-bfc7-9ffb49c66b2f','2026-04-13 08:39:52.462084','2026-04-13 08:39:52.462084',NULL,'draft',1,'{}',NULL,NULL),
('8a0abb70-5310-41ae-8479-2897c61b4ca6','Член Правления','Участвует в заседаниях Правления, вносит предложения по развитию бизнеса, оценивает риски, контролирует выполнение ключевых показателей деятельности компании, представляет интересы определенного функционального направления при принятии решений.','Члены Правления','[{"level": "высокое", "trait": "Ответственность"}, {"level": "выше среднего", "trait": "Объективность"}, {"level": "высокое", "trait": "Внимательность к деталям"}, {"level": "среднее", "trait": "Инициативность"}, {"level": "высокое", "trait": "Принципиальность"}]','[{"name": "Экспертиза в своей области", "required_level": 9}, {"name": "Системное мышление", "required_level": 9}, {"name": "Анализ данных", "required_level": 8}, {"name": "Критическое мышление", "required_level": 8}, {"name": "Стратегическое планирование", "required_level": 8}, {"name": "Деловая этика", "required_level": 9}]','2217c8c3-7907-4dc1-bfc7-9ffb49c66b2f','2026-04-13 08:39:52.562436','2026-04-13 08:39:52.562436',NULL,'draft',1,'{}',NULL,NULL),
